import json, subprocess, pathlib
root = pathlib.Path('/home/damien/Liatrio/repos/forge-program-tracker')
local = json.loads((root/'.github/ruleset-config.json').read_text())
octo = json.loads(subprocess.check_output(['gh','api','apps/octo-sts','--jq','.id'], text=True))
local['bypass_actors'] = sorted({(a['actor_type'], a['actor_id'], a.get('bypass_mode','always')) for a in (local.get('bypass_actors') or [])} | {('Integration', octo, 'always')})
local['bypass_actors'] = [
    {'actor_type': t, 'actor_id': i, 'bypass_mode': b} if t != 'RepositoryRole' or b != 'always' else {'actor_type': t, 'actor_id': i}
    for t, i, b in sorted(local['bypass_actors'])
]
live = json.loads(subprocess.check_output(['gh','api','repos/liatrio-labs/forge-program-tracker/rulesets/13354192'], text=True))

def norm(data):
    rules=[]
    for rule in data.get('rules',[]):
        rule=dict(rule)
        if rule['type']=='required_status_checks':
            params=dict(rule.get('parameters') or {})
            params.setdefault('do_not_enforce_on_create', False)
            rule['parameters']=params
        elif rule['type']=='pull_request':
            params=dict(rule.get('parameters') or {})
            params.setdefault('required_reviewers', [])
            rule['parameters']=params
        rules.append(rule)
    out={
        'name': data['name'],
        'target': data['target'],
        'enforcement': data['enforcement'],
        'conditions': data['conditions'],
        'rules': sorted(rules, key=lambda r: r['type']),
        'bypass_actors': sorted([
            {
                'actor_type': a['actor_type'],
                'actor_id': a['actor_id'],
                **({'bypass_mode': a['bypass_mode']} if 'bypass_mode' in a else {})
            }
            for a in data.get('bypass_actors',[])
        ], key=lambda a: (a['actor_type'], a['actor_id'], a.get('bypass_mode','always')))
    }
    return out
print('ruleset_parity=' + str(norm(local)==norm(live)).lower())
